import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import java.util.*;

public class SolutionTest {

    @Test
    void typicalCase() {
        // 1 freq=1, 2 freq=2, 3 freq=3 => least-2: [1,2]
        int[] nums = {1, 2, 2, 3, 3, 3};
        assertArrayEquals(new int[]{1, 2}, new Solution().leastKFrequent(nums, 2));
    }

    @Test
    void tiebreakByValueAscending() {
        // 7 freq=1, 3 freq=2, 5 freq=2; least-2: 7 (freq=1) then tiebreak 3 < 5 => [7,3]
        int[] nums = {5, 5, 3, 3, 7};
        assertArrayEquals(new int[]{7, 3}, new Solution().leastKFrequent(nums, 2));
    }

    @Test
    void kEqualsDistinctCount() {
        // k=3 equals number of distinct values => return all three least-freq order
        // 1 freq=1, 2 freq=2, 4 freq=3 => [1,2,4]
        int[] nums = {4, 4, 4, 2, 2, 1};
        assertArrayEquals(new int[]{1, 2, 4}, new Solution().leastKFrequent(nums, 3));
    }

    @Test
    void kExceedsDistinctCount() {
        // k=5 but only 2 distinct values => return both in least-freq order
        // 10 freq=1, 20 freq=3 => [10,20]
        int[] nums = {10, 20, 20, 20};
        assertArrayEquals(new int[]{10, 20}, new Solution().leastKFrequent(nums, 5));
    }

    @Test
    void emptyInput() {
        assertArrayEquals(new int[]{}, new Solution().leastKFrequent(new int[]{}, 2));
    }

    @Test
    void allSameFrequency() {
        // 10,20,30 each appear twice; tiebreak asc value => [10,20,30]; least-2: [10,20]
        int[] nums = {10, 10, 20, 20, 30, 30};
        assertArrayEquals(new int[]{10, 20}, new Solution().leastKFrequent(nums, 2));
    }

    @Test
    void singleElement() {
        int[] nums = {42};
        assertArrayEquals(new int[]{42}, new Solution().leastKFrequent(nums, 1));
    }
}
